"use client"

import { useEffect, useState } from 'react'

type Overview = {
  total_users: number
  total_devices: number
  total_bound_devices: number
  total_openwrt_nodes: number
}

export default function DashboardPage() {
  const [data, setData] = useState<Overview | null>(null)
  const [error, setError] = useState('')

  useEffect(() => {
    fetch('/api/admin/stats/overview', { credentials: 'include' })
      .then(async (res) => {
        if (!res.ok) throw new Error('加载失败')
        return res.json()
      })
      .then(setData)
      .catch(() => setError('暂时无法获取后台统计，请先用 root 账号登录用户前台，再访问后台。'))
  }, [])

  return (
    <div>
      <div className="header-row"><h2>仪表盘</h2></div>
      {error ? <div className="card">{error}</div> : !data ? <div className="card">加载中…</div> : (
        <div className="card-grid">
          <div className="card"><div className="label">总用户数</div><div className="value">{data.total_users}</div></div>
          <div className="card"><div className="label">总设备数</div><div className="value">{data.total_devices}</div></div>
          <div className="card"><div className="label">已绑定设备数</div><div className="value">{data.total_bound_devices}</div></div>
          <div className="card"><div className="label">OpenWrt 节点数</div><div className="value">{data.total_openwrt_nodes}</div></div>
        </div>
      )}
    </div>
  )
}
